  targetPosRef: React.MutableRefObject<Vector3>;
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  projectileType?: ProjectileType;
  // New Props via Player
  enemiesDataRef?: React.MutableRefObject<EnemyData[]>;
