export const calculateItemCP = (item: Item): number => {
    // Exclude consumables from CP
    if (item.type === 'POTION' || item.type === 'CORE' || item.type === 'REVIVE') return 0;
    if (!item.stats) return 0;

    let cp = 0;
    const s = item.stats;

    if (s.damage) cp += s.damage * 10;
    if (s.maxHealth) cp += s.maxHealth * 1;
    if (s.defense) cp += s.defense * 8;
    if (s.moveSpeed) cp += s.moveSpeed * 500;
    if (s.fireRate) cp += s.fireRate * 100;
    if (s.regen) cp += s.regen * 50;
    if (s.manaRegen) cp += s.manaRegen * 50;
    if (s.critRate) cp += s.critRate * 500;
    if (s.critDamage) cp += s.critDamage * 100;
    if (s.cooldownReduction) cp += s.cooldownReduction * 500;
    if (s.skillDamage) cp += s.skillDamage * 100;
    if (s.multishot) cp += s.multishot * 200;
    if (s.dodge) cp += s.dodge * 500;

    const rarityMult = {
        'COMMON': 1,
        'RARE': 1.2,
        'EPIC': 1.5,
        'LEGENDARY': 2.0,
        'MYTHIC': 3.0
    };

    return Math.floor(cp * rarityMult[item.rarity]);
};

export const calculateTotalCP = (stats: PlayerStats): number => {
    let cp = 0;
    cp += stats.damage * 10;
    cp += stats.maxHealth * 1;
    cp += stats.defense * 8;
    cp += stats.moveSpeed * 50; 
    cp += stats.fireRate * 50;
    cp += stats.regen * 50;
    cp += stats.manaRegen * 50;
    cp += stats.critRate * 500;
    cp += stats.critDamage * 100;
    cp += stats.cooldownReduction * 500;
    cp += stats.skillDamage * 100;
    cp += stats.multishot * 200;
    cp += stats.dodge * 500;
    return Math.floor(cp);
};

const calculateStats = (base: PlayerStats, equipment: GameState['equipment'], rageMode: boolean = false, sprintActive: boolean = false) => {
  const final = { ...base };
  const sets: Record<string, number> = {};

  Object.values(equipment).forEach(item => {
    if (item) {
        if (item.stats) {
            Object.entries(item.stats).forEach(([key, val]) => {
                const k = key as keyof PlayerStats;
                let v = val as number;

                if (item.type === 'WEAPON' && k === 'damage') v *= 0.5;
                if (item.type === 'ARMOR' && k === 'defense') v *= 0.5;

                if (k === 'moveSpeed' || k === 'fireRate') {
                     // @ts-ignore
                     final[k] += v;
                } else if (k === 'cooldownReduction') {
                     final[k] = Math.min(0.75, final[k] + v);
                } else {
                     // @ts-ignore
                     final[k] += v;
                }
            });
        }
        if (item.setName) {
            sets[item.setName] = (sets[item.setName] || 0) + 1;
        }
    }
  });

  Object.entries(sets).forEach(([setName, count]) => {
      if (count >= 3) {
          const setItem = Object.values(equipment).find(i => i?.setName === setName);
          if (setItem && setItem.setBonusStats) {
              Object.entries(setItem.setBonusStats).forEach(([stat, val]) => {
                  if (stat === 'damage' || stat === 'moveSpeed' || stat === 'fireRate') {
                      // @ts-ignore
                      final[stat] *= (1 + val);
                  } else {
                      // @ts-ignore
                      final[stat] += val;
                  }
              });
          }
      }
  });

  if (equipment.weapon && equipment.weapon.projectileType === 'MAGIC') {
      final.fireRate *= 0.5;
  }

  if (rageMode) {
      final.fireRate *= 2.0;
  }

  if (sprintActive) {
      final.moveSpeed *= 2.0;
  }

  if (final.multishot > 7) final.multishot = 7;

  return final;
};

// --- ENVIRONMENT GENERATION ---
const generateObstacles = (): Obstacle[] => {
    const obs: Obstacle[] = [];

    const townRadius = 20;
    const denseForestStart = 28;
    const mapLimit = ARENA_SIZE / 2;

    // 1. Generate Town Fence Perimeter (Radius ~20)
    // Leave 4 gaps for gates (N, S, E, W)
    const perimeterCount = 40;
    for (let i = 0; i < perimeterCount; i++) {
        const angle = (i / perimeterCount) * Math.PI * 2;
        // Skip angles near PI/2, PI, 3PI/2, 0 (0, 90, 180, 270 deg)
        // Deg: 0, 90, 180, 270
        const deg = (angle * 180 / Math.PI + 360) % 360;
        if (Math.abs(deg - 0) < 15 || Math.abs(deg - 90) < 15 || Math.abs(deg - 180) < 15 || Math.abs(deg - 270) < 15) {
            continue;
        }

        const x = Math.cos(angle) * townRadius;
        const z = Math.sin(angle) * townRadius;
        obs.push({
            id: 10000 + i,
            position: new Vector3(x, 0, z),
            radius: 0.5,
            type: 'FENCE',
            rotation: -angle, // Face inward/tangent
            scale: 1
        });
    }

    // 2. Generate Dense Forest (Radius 28 to Limit)
    // We want a lot of trees to create darkness/density
    const treeCount = 400; 
    for(let i = 0; i < treeCount; i++) {
        const angle = Math.random() * Math.PI * 2;
        // Biased distribution towards outer edge for more density there? 
        // Uniform ring distribution: sqrt(random)
        const minR = denseForestStart;
        const maxR = mapLimit + 10; // Go slightly beyond visual ground
        const r = Math.sqrt(Math.random() * (maxR*maxR - minR*minR) + minR*minR);

        const x = Math.cos(angle) * r;
        const z = Math.sin(angle) * r;

        obs.push({
            id: Math.random(),
            position: new Vector3(x, 0, z),
            radius: 1.0,
            type: 'TREE',
            scale: 1.5 + Math.random() * 2.5 // Taller trees
        });
    }

    // 3. Scattered Rocks in the Forest
    for(let i=0; i<50; i++) {
        const angle = Math.random() * Math.PI * 2;
        const minR = denseForestStart;
        const maxR = mapLimit;
        const r = Math.sqrt(Math.random() * (maxR*maxR - minR*minR) + minR*minR);

        const x = Math.cos(angle) * r;
        const z = Math.sin(angle) * r;

        obs.push({
            id: Math.random(),
            position: new Vector3(x, 0, z),
            radius: 1.5,
            type: 'ROCK',
            scale: 0.5 + Math.random()
        });
    }

    // Add House explicitly in town? Maybe remove house to keep town clean circle
    // obs.push({ id: 9999, position: new Vector3(15, 0, 15), radius: 4, type: 'HOUSE', scale: 1 });

    return obs;
};

const generateCrates = (): CrateData[] => {
    // Generate Crates mostly in the forest or near fence
    return new Array(25).fill(0).map((_, i) => {
        const angle = Math.random() * Math.PI * 2;
        const dist = 22 + Math.random() * 30; // Outside fence
        return {
            id: i,
            active: true,
            position: new Vector3(Math.cos(angle)*dist, 1, Math.sin(angle)*dist),
            rotation: Math.random() * Math.PI,
            hp: 30,
            maxHp: 30
        };
    });
};

const generateUpgradeOptions = (heroClass: HeroClass): Upgrade[] => {
    const options: Upgrade[] = [];
    const pool = UPGRADES_POOL.filter(u => u.classType === undefined || u.classType === heroClass);

    for (let i = 0; i < 3; i++) {
        if (pool.length === 0) break;
        const index = Math.floor(Math.random() * pool.length);
        options.push({ ...pool[index], id: Math.random().toString() });
    }
    return options;
};

