import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Text } from '@react-three/drei';
import { Vector3, Group } from 'three';
import { useGameStore } from '../store';
import { GameStatus } from '../types';
import { COLORS, SHOP_POSITIONS } from '../constants';

const ShopBuilding: React.FC<{
    position: number[]; // Expecting array from constants
    label: string;
    color: string;
    onClick: () => void;
    icon: string;
}> = ({ position, label, color, onClick, icon }) => {
    const groupRef = useRef<Group>(null);
    const { playerPosition } = useGameStore();

    useFrame((state) => {
        if (!groupRef.current) return;

        // Floating label
        const dist = playerPosition.distanceTo(new Vector3(position[0], position[1], position[2]));
        if (dist < 8) {
            groupRef.current.position.y = Math.sin(state.clock.elapsedTime * 2) * 0.2;
        } else {
            groupRef.current.position.y = 0;
        }
    });

    return (
        <group position={[position[0], position[1], position[2]]} onClick={(e) => { e.stopPropagation(); onClick(); }}>
            {/* Base */}
            <mesh position={[0, 1.5, 0]} castShadow receiveShadow>
                <boxGeometry args={[4, 3, 4]} />
                <meshStandardMaterial color="#475569" roughness={0.8} />
            </mesh>

            {/* Roof */}
            <mesh position={[0, 4, 0]}>
                <coneGeometry args={[3.5, 2.5, 4]} />
                <meshStandardMaterial color={color} />
            </mesh>

            {/* Door */}
            <mesh position={[0, 1, 2.1]}>
                <boxGeometry args={[1.5, 2, 0.2]} />
                <meshStandardMaterial color="#1e293b" />
            </mesh>

            {/* Label */}
            <group ref={groupRef}>
                <Text
                    position={[0, 6.5, 0]}
                    fontSize={1.2}
                    color="white"
                    outlineWidth={0.1}
                    outlineColor="black"
                    anchorX="center"
                    anchorY="middle"
                    billboard
                >
                    {icon}
                </Text>
                <Text
                    position={[0, 5.5, 0]}
                    fontSize={0.6}
                    color="white"
                    outlineWidth={0.05}
                    outlineColor="black"
                    anchorX="center"
                    anchorY="middle"
                    billboard
                >
                    {label}
                </Text>
            </group>

            {/* Interaction Ring on Ground */}
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.1, 0]}>
                <ringGeometry args={[3.5, 3.8, 32]} />
                <meshBasicMaterial color={color} transparent opacity={0.5} />
            </mesh>
        </group>
    );
};

export const ShopStructures: React.FC = () => {
    const { openSpecificShop, status } = useGameStore();

    if (status !== GameStatus.PLAYING && status !== GameStatus.PAUSED && status !== GameStatus.SHOP) return null;

    // Use SHOP_POSITIONS from constants to ensure alignment with minimap and requested layout
    const supplies = SHOP_POSITIONS.find(s => s.type === 'SUPPLIES')!;
    const blacksmith = SHOP_POSITIONS.find(s => s.type === 'BLACKSMITH')!;
    const pets = SHOP_POSITIONS.find(s => s.type === 'PETS')!;
    const summon = SHOP_POSITIONS.find(s => s.type === 'SUMMON')!;

    return (
        <group>
            <ShopBuilding 
                position={supplies.position} 
                label="SUPPLIES" 
                color={supplies.color}
                onClick={() => openSpecificShop('SUPPLIES')}
                icon="⚗️"
            />

            <ShopBuilding 
                position={blacksmith.position} 
                label="BLACKSMITH" 
                color={blacksmith.color}
                onClick={() => openSpecificShop('BLACKSMITH')}
                icon="🔨"
            />

            <ShopBuilding 
                position={pets.position} 
                label="PETS" 
                color={pets.color}
                onClick={() => openSpecificShop('PETS')}
                icon="👻"
            />

            <ShopBuilding 
                position={summon.position} 
                label="SUMMON" 
                color={summon.color} 
                onClick={() => openSpecificShop('SUMMON')}
                icon="🎲"
            />
        </group>
    );
};

